% popper assumes head predicates declared in bias do not appear in any body of rules in BK
% eqo(X,Y):- eqo(Y,X). 
% eqo(X,Y):- eqo(X,Z), eqo(Z,Y).

% also constraint bodies are horn clause, therefore no negation
simm(X,Y):- simm(Y,X).
% example(0,C1,5,C2) :- eqo(C1,C2),dblp(C1,_,_,_,_), acm(C2,_,_,_,_).
simm(X,Y) :- sim(X,Y,S).


